var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"휴, 이걸로 청소 끝-","JPN":"ふう～これでお掃除完了！","ENG":"Whew, I'm finally done cleaning up.","TWN":"呼，都處理乾淨了-"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"이제 운동회가 방해 받을 일은 없으려나.","JPN":"もう運動会を邪魔する者はいないわよね。","ENG":"Now, I don't have to worry about them interfering with the Field Day.","TWN":"這下運動會應該不會受到影響了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"당신들도 걸을 수 있으면 이제 그만 돌아가.","JPN":"あなたたちも歩けるならそろそろ帰ってね。","ENG":"If you can walk, you'd better leave now.","TWN":"你們要是能走的話，現在也回去吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"근방에 있던 침식체들은 모두 처리했지만 잔류 침식파가 남아 있거든.","JPN":"近くにいた侵食体は全部片付けたけど、残留侵食波があるの。","ENG":"I took care of all the C.O.s around here, but their Corruption rays still remain.","TWN":"附近的侵蝕體雖然已經都處理掉了，但還殘留著侵蝕波。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"큰 문제는 없겠지만, 굳이 위험을 감수할 필요는 없잖아?","JPN":"大した問題はないけど、わざわざ危険な場所にいる必要はないでしょう？","ENG":"I doubt they'd cause you a serious problem, but you don't have to risk it, right?","TWN":"雖然應該沒什麼大問題，但也沒必要把自己放在危險裡吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"저기, 실례지만...... 당신은 카운터 아카데미의 학생으로 보이진 않는데요.","JPN":"あの、失礼ですが……あなたはカウンターアカデミーの生徒には見えませんね。","ENG":"Erm, I'm sorry, but you don't look like you're a student at the Counter Academy.","TWN":"那個，很抱歉……你看起來好像不是制裁者學院的學生。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"혹시 안전을 위해 고용된 용병 같은 겁니까?","JPN":"安全のために雇われた傭兵でしょうか？","ENG":"Are you a mercenary hired to secure the perimeter?","TWN":"難道是學院出於安全考慮雇傭的傭兵？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그런 건 아니야. 그냥 학생 보호자로 온 사람일 뿐이지.","JPN":"違うわ。生徒の保護者として来たの。","ENG":"Not exactly. I'm here with a student.","TWN":"不是，我就是一個學生的監護人。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"굳이 말하자면...... 학부모 같은 거려나?","JPN":"つまり……母親みたいな？","ENG":"Her chaperone, if you will.","TWN":"非要說的話……就是家長之類的？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"그, 그게 대체 무슨 뜻입니까?","JPN":"さ、さっぱりわかりませんが……","ENG":"W-what do you mean?","TWN":"你，你這話是什麼意思？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"평범한 학부모가 침식체들을 쓰러트릴 수 있을 리 없잖아요!","JPN":"普通の人が侵食体を倒せるなんて、あり得ません！","ENG":"There's no way an ordinary chaperone can defeat C.O.s like that!","TWN":"平凡的家長不可能打倒侵蝕體！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"애초에 여기서 왜 침식체가 나타난 건지 그 원인을 밝혀야 돼요.","JPN":"その前になぜここに侵食体が現れたのか原因を究明しないと！","ENG":"We must know why those C.O.s showed up to begin with.","TWN":"必須查明這裡一開始為什麼會出現侵蝕體。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"시청자들에겐 알 권리가 있으니까요!","JPN":"視聴者には知る権利があります！","ENG":"Our viewers have the right to know!","TWN":"觀眾們有權知道真相！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"응. 난 그런 얘기 잘 몰라.","JPN":"うーん、私ね、そういう話は詳しくないの。","ENG":"Well, I don't know what you're talking about.","TWN":"嗯，我不知道那些事。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그렇게 원인이 궁금하면 둘이 알아서 조사하도록 해.","JPN":"そんなに原因が知りたいなら二人で調査するといいわ。","ENG":"If you're so curious, good luck figuring it out between you two.","TWN":"想知道的話，你們兩個自己去調查吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"하지만 방송에서 내 얼굴이나 목소리가 나왔다간......","JPN":"でも放送に私の顔や声を流すつもりなら……","ENG":"But you'd better not show my face or play my voice on your show,","TWN":"不過如果電視上出現我的臉或者聲音……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"알지?","JPN":"どうなるか、わかってるわよね？","ENG":"or...","TWN":"知道吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};